"""
MKT Original Commentary — Matthew chapters 5–6
Run: python3 scripts/zc-original-matthew-5-6.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json
- data/translation/glossary-greek.json (makarios, dikaiosynē, ponerou, epiousion)
- data/commentary/mkt-original/matthew.json (existing entries carried forward)

Key decisions in this range:
- makarios (5:3ff): state-of-blessedness, not performative praise — already treated in 5:3
- dikaiosynē (5:6,10,20; 6:1,33): one word spans legal standing and moral character; noted per verse
- ek tou ponerou (5:37): retained as "the evil one" following MKT; ambiguity noted
- epiousion (6:11): "daily" retained; textual rarity flagged
- moraino (5:13): "loses saltiness" — but also "make foolish" (mōros cognate)
- apechousin (6:2,5,16): papyrological receipt formula "paid in full"
- hupokritai (6:2,5,16): theater-actor origin noted once at 6:2, referenced thereafter
- oligopistos (6:30): Jesus's coined compound word for disciples of weak trust
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "5": {
    "1": '<p><strong>anabas eis to oros</strong> — having gone up into the mountain — <em>anabas</em> is an aorist participle of <em>anabainō</em>, establishing ascent as the frame for what follows. Mountains in Matthew carry covenantal freight (cf. 4:8, 17:1, 28:16); the location is not incidental. <em>Ekathisen</em> (he sat down) is the posture of the authoritative Jewish teacher: a rabbi sat to teach formally. The crowds draw near (v.1), but the address is directed to the disciples (<em>proselthon autō hoi mathetai autou</em>), marking this as discipleship instruction rather than a general ethical manifesto.</p>',
    "2": '<p><strong>anoixas to stoma autou</strong> — having opened his mouth — a Semitic idiom (cf. Job 33:2; Ps 78:2) signaling formal, deliberate, weighty speech, not casual conversation. <em>Edidasken</em> is the imperfect of <em>didaskō</em> — he was teaching them — a continuous action extending through the discourse. The imperfect is inceptive: "he began to teach and continued doing so."</p>',
    "4": '<p><strong>penthountes</strong> — those who mourn (<em>pentheō</em>, present active participle) — an ongoing state of grief, not a single act of weeping. The verb is used for mourning the dead (cf. Gen 23:2 LXX) and for penitential grief over sin; in context both senses may be live. <strong>Paraklēthēsontai</strong> — they will be comforted — future passive divine; the agent is God (the passive avoids the divine name). The same root as the Paraclete (<em>paraklētos</em>) in John 14–16.</p>',
    "5": '<p><strong>praeis</strong> — the meek (<em>praus</em>) — not passive weakness but the quality of controlled, disciplined strength that does not assert itself for personal advantage. The word is used of the trained warhorse and of Moses (Num 12:3 LXX: <em>praus sphodra</em>). <strong>Klēronomēsousin tēn gēn</strong> — will inherit the earth — a direct echo of Ps 37:11 LXX (<em>hoi de praeis klēronomēsousin gēn</em>); the Beatitude functions as a fulfillment citation without attribution, assuming the audience knows the Psalm.</p>',
    "6": '<p><strong>peinontes kai dipsontes tēn dikaiosynēn</strong> — hungering and thirsting for righteousness — both present active participles, denoting ongoing, urgent appetite. <em>Dikaiosynē</em> (G1343) spans legal standing before God and moral conformity to his will; both senses are alive in Matthew\'s usage. <em>Chortasthēsontai</em> — they will be filled/satisfied — <em>chortazō</em> is agricultural: the filling of animals in a stall, then by extension anyone satisfied to the full. The hunger is intense; the filling will be complete.</p>',
    "7": '<p><strong>eleēmones</strong> — the merciful (<em>eleos</em>-group, corresponding to Hebrew <em>hesed</em>) — those who show active covenant loyalty, not merely feelings of sympathy. <strong>Eleēthēsontai</strong> — will be shown mercy — future passive divine: God will show them mercy. The Beatitude is not a commercial transaction but a correlation: those who inhabit the world as mercy-givers live in the register where mercy is received.</p>',
    "8": '<p><strong>katharoi tē kardia</strong> — pure in heart — <em>katharos</em> in cultic usage meant ritually clean; here it is applied to the <em>kardia</em> (heart), the biblical center of will, intellect, and moral intention. The antithesis is not ritual impurity but divided loyalty (cf. Jas 4:8, <em>dipsychoi</em>, double-minded). <strong>Ton theon opsontai</strong> — they will see God — <em>horaō</em> future; the eschatological vision of God (cf. Ps 11:7; Rev 22:4). Purity of the inner faculty is the condition for the ultimate perception.</p>',
    "9": '<p><strong>eirēnopoioi</strong> — peacemakers — a compound unique to Matthew in the NT: <em>eirēnē</em> (peace, shalom) + <em>poieō</em> (make, do); those who actively construct peace rather than merely possess it. <strong>Huioi theou klēthēsontai</strong> — they will be called sons of God — future passive: God will name them his children. In biblical usage, to be "called" by God is to be constituted as what the name declares, not merely titled.</p>',
    "10": '<p><strong>dedioxmenoi</strong> — those who have been persecuted (<em>diōkō</em>, perfect passive participle) — the perfect marks completed action with continuing effect: they already bear the mark of persecution received. The reason: <em>heneken dikaiosynēs</em> — because of righteousness — the same <em>dikaiosynē</em> as v.6, the pursuit of God\'s right order that attracts opposition. The reward is identical to v.3: <em>autōn estin hē basileia tōn ouranōn</em> — present tense brackets the eight Beatitudes (vv.3, 10), framing them as a single structure.</p>',
    "11": '<p><strong>oneidisōsin hymas kai diōxōsin</strong> — insult you and persecute you — <em>oneidizō</em> is active shaming, verbal attack designed to strip social honor. The shift from third person (vv.3-10) to second person plural (<em>hymas</em>) personalizes the eighth Beatitude. <strong>Pseudomenoi</strong> — falsely — the adjectival participle specifies slander, not merely erroneous accusation. <strong>Heneken emou</strong> — because of me — the ground of persecution shifts: not righteousness in the abstract but allegiance to Jesus specifically.</p>',
    "12": '<p><strong>chairete kai agalliasthe</strong> — rejoice and be exceedingly glad — <em>chairō</em> is standard joy; <em>agalliaō</em> intensifies it: exultation, jubilant leaping (used for Messianic celebration in Ps 14:7 LXX; Luke 1:44). <strong>Misthos</strong> — reward (<em>misthos</em>) — the commercial word for wages owed, not a gift; the framework is one of rightful payment. <strong>Houtōs gar edioxan tous prophētas</strong> — for so they persecuted the prophets — <em>edioxan</em> aorist: historical completed act; the suffering disciples are identified with the prophetic tradition.</p>',
    "13": '<p><strong>hymas este to halas tēs gēs</strong> — you are the salt of the earth — <em>hymas</em> is emphatic by position: you (and no one else) are. <em>Halas</em> (salt) in the ancient world preserved, flavored, and was associated with covenant fidelity (Lev 2:13, "covenant of salt"). <strong>Moranthe</strong> — should lose its saltiness — aorist passive subjunctive of <em>morainō</em>: to become flat, tasteless, foolish. The same verb means "to make foolish" (cognate with <em>mōros</em>, fool — cf. v.22); the salt that loses its saltiness becomes <em>mōros</em> in both senses. <em>En tini alisthēsetai</em> — by what will it be salted again? — a rhetorical impossibility.</p>',
    "14": '<p><strong>to phōs tou kosmou</strong> — the light of the world — contrasting scale with v.13: salt is for the earth (<em>gē</em>); light is for the world (<em>kosmos</em>). <em>Polis epanō orous keimenē</em> — a city set on a hill — present passive participle, already in place; the city does not choose visibility, it cannot avoid it. The metaphor reinforces the communal dimension: the disciples together constitute the visible settlement.</p>',
    "15": '<p><strong>kaiousi lychnon</strong> — they light a lamp — present active, a generic statement of normal practice. <em>Modion</em> — a bushel/measuring vessel, typically a wooden container of about 8.75 liters; placing a lamp under it extinguishes it. <em>Lychnian</em> — the lampstand — the proper location for a lamp; <em>lampei pasin tois en tē oikia</em> — it gives light to all who are in the house. The domestic scale prepares for v.16\'s address to a wider audience.</p>',
    "16": '<p><strong>lampsatō to phōs hymōn</strong> — let your light shine (<em>lampō</em>, aorist imperative) — the only imperative in the salt-and-light passage; the preceding metaphors describe what the disciples are, this commands what they must not suppress. <em>Emprosthen tōn anthrōpōn</em> — before people — visibility is the point. The purpose clause (<em>hopōs</em>): that they may see your <em>kala erga</em> (good works) and glorify — not you, but <em>ton patera hymōn ton en tois ouranois</em> — your Father in heaven. Visibility is not self-promotion; it is the medium through which the Father is glorified.</p>',
    "18": '<p><strong>iōta hen ē mia keraia</strong> — one iota or one stroke — <em>iōta</em> is the Greek transliteration of Hebrew <em>yod</em> (י), the smallest letter; <em>keraia</em> (horn, serif) is the smallest distinguishing mark between Hebrew letters (e.g., ד and ר). Together they represent the minimum possible unit of textual precision. <strong>Ou mē parelthē</strong> — will by no means pass away — double negative for emphatic negation, the strongest denial available in Greek. <em>Heōs an panta genētai</em> — until all things come to pass — the same verb (<em>ginomai</em>) as <em>plērōsai</em> in v.17; fulfillment of the Law coincides with fulfillment of all things.</p>',
    "19": '<p><strong>hos ean lysē mian tōn entolōn toutōn tōn elachistōn</strong> — whoever breaks one of the least of these commandments — <em>lyō</em> is the same root as <em>katalyō</em> in v.17; to break a commandment is the micro-scale equivalent of abolishing the Law. The ranking system (<em>elachistos</em>/least, <em>megas</em>/great) is recognized within the kingdom: some commandments are lesser, but none are dismissible. <em>Klēthēsetai elachistos</em> — will be called least — passive future divine: their standing in the kingdom reflects their practice, not merely their teaching.</p>',
    "20": '<p><strong>ean mē perisseusē hē dikaiosynē hymōn pleon tōn grammateōn kai Pharisaiōn</strong> — unless your righteousness exceeds that of the scribes and Pharisees — <em>perisseusē</em> (aorist subjunctive of <em>perisseuō</em>, to abound, exceed) with <em>pleon</em> (more than) sets an explicit comparative bar. The scribes and Pharisees were the recognized specialists in Torah observance; "exceeding" them is not a call to more meticulous rule-keeping but to a different kind of <em>dikaiosynē</em> — one that addresses the heart (as the antitheses of vv.21–48 will demonstrate). <em>Ou mē eiselthēte</em> — you will certainly not enter — the same double-negative construction as v.18.</p>',
    "22": '<p><strong>orgizomenos tō adelphō autou</strong> — being angry at his brother or sister — present participle, ongoing anger as opposed to a momentary flash. The verse escalates through three levels of offense and corresponding courts: (1) ongoing anger — liable to local judgment (<em>krisei</em>); (2) <em>rhaka</em> — probably from Aramaic <em>rēqā</em> (empty one, blockhead), a term of contemptuous dismissal — liable to the Sanhedrin (<em>synedriō</em>); (3) <em>mōre</em> (fool, from <em>mōros</em>) — liable to the Gehenna of fire (<em>geennan tou pyros</em>). <em>Geenna</em> refers to the Valley of Hinnom outside Jerusalem, used as a metaphor for final judgment.</p>',
    "23": '<p><strong>ean oun prospherēs to dōron sou</strong> — if then you are offering your gift — <em>prospherō</em> present active subjunctive: in the act of offering, the memory arrives. The altar context places this in the Temple cult. <em>Kakei mnesthēs</em> — and there you remember — <em>mnaomai</em> aorist passive subjunctive: a sudden recollection. The scenario presupposes a grievance held against the offerer by the brother or sister (<em>echei ti kata sou</em> — has something against you), not merely that the offerer feels guilty.</p>',
    "24": '<p><strong>aphes ekei to dōron sou</strong> — leave your gift there — <em>aphiēmi</em> aorist imperative: a decisive action. The gift is left at the altar, not abandoned. <em>Hypage prōton</em> — go first — the adverb <em>prōton</em> establishes priority: reconciliation precedes cultic offering. <em>Diallagēthi tō adelphō sou</em> — be reconciled to your brother or sister — <em>diallassō</em> aorist passive imperative: reconciliation is received as much as performed; it requires both parties. The sequence is: leave → go → be reconciled → return → offer.</p>',
    "25": '<p><strong>euthopon</strong> — quickly, while on the way (<em>euthys</em> + <em>en tē hodō met autou</em>) — the urgency is temporal: settle before reaching the court. <em>Antidikos</em> — adversary/plaintiff (<em>anti</em> + <em>dikē</em>, lawsuit) — the technical term for the opposing party in litigation. The sequence of officials (<em>kritēs</em>/judge → <em>hyperetēs</em>/officer → <em>phylakē</em>/prison) traces the legal process to its worst outcome, extending the anger-reconciliation theme of vv.22–24.</p>',
    "26": '<p><strong>ou mē exelthēs</strong> — you will certainly not come out — double negative for emphatic futurity. <em>Heōs an apodōs ton eschaton kodrantēn</em> — until you have paid the last <em>kodrantes</em> — the <em>kodrantes</em> was the smallest Roman coin, a quadrans worth a quarter of an as; <em>eschaton</em> (last) reinforces completeness: not one smallest payment will be waived. The legal metaphor underscores the completeness of the moral debt if reconciliation is not pursued.</p>',
    "27": '<p><strong>ou moicheuseis</strong> — you shall not commit adultery — the direct citation of the seventh commandment (Exod 20:14 LXX). The formula <em>ēkousate hoti errethē</em> (you have heard that it was said) follows the pattern of v.21; the passive <em>errethē</em> leaves the speaker unnamed, but the contrast introduced by <em>egō de legō hymin</em> (but I tell you) in v.28 sets Jesus\'s authority alongside — not against — the Torah.</p>',
    "28": '<p><strong>ho blepōn gynaika pros to epithymēsai autēn</strong> — the one who looks at a woman in order to desire her — <em>pros to epithymēsai</em> is an articular infinitive of purpose: the look is characterized by its intent. <em>Epithymeō</em> (G1937) is the LXX word for "covet" in the tenth commandment (Exod 20:17); Jesus draws the seventh commandment into the orbit of the tenth. <strong>Ēdē emoicheusen autēn en tē kardia autou</strong> — has already committed adultery with her in his heart — <em>ēdē</em> (already) marks the act as completed at the moment of intentional looking, not pending physical action.</p>',
    "29": '<p><strong>ei de ho ophthalmos sou ho dexios skandalizei se</strong> — if your right eye causes you to stumble (<em>skandalizō</em>, to put a snare, cause to fall) — the right eye (<em>dexios</em>, valued, dominant) is chosen precisely because it is the more precious one; the hyperbole shocks. <em>Exele auton kai bale apo sou</em> — tear it out and throw it from you — aorist imperatives: decisive, immediate action. <em>Sympherei gar soi</em> — for it is better for you (literally, it profits you) — <em>sympherō</em> is used in commercial calculation; losing a body part is preferable to the whole body (<em>holon to soma</em>) being thrown into Gehenna.</p>',
    "30": '<p><strong>hē dexia sou cheir</strong> — your right hand — the dominant, more valued hand, parallel to the right eye of v.29. The repeated hyperbole of self-amputation is not a literal prescription but a graphic measure of moral seriousness. <em>Apoles hen tōn melōn sou</em> — that one of your members be lost — <em>apollymi</em> aorist subjunctive: the destruction of a part to preserve the whole. <em>Geenna</em> recurs as in v.29; the eschatological framework governs both illustrations.</p>',
    "31": '<p><strong>hos an apolyē tēn gynaika autou</strong> — whoever divorces his wife — the citation draws on Deut 24:1 (the practice of <em>apostasion</em> = certificate of divorce/release). The Pharisaic debate over the grounds (<em>ervat dabar</em>, "some indecency": interpreted broadly by Hillel and narrowly by Shammai) is the unstated background. Jesus addresses the mechanism, not merely the grounds.</p>',
    "32": '<p><strong>parektos logou porneias</strong> — except for the matter of sexual immorality — <em>porneia</em> (G4202) covers a range of sexual violations; the exception clause is unique to Matthew (cf. Mark 10:11-12, Luke 16:18, which have no exception). <em>Poiei autēn moicheuthenai</em> — makes her commit adultery — <em>moicheuō</em> passive: she is the victim of the situation created by the divorce. <em>Apolelymenen</em> is a perfect passive participle marking her ongoing status as the divorced woman.</p>',
    "33": '<p><strong>ouk epiorkēseis, apodōseis de tō kyriō tous horkous sou</strong> — you shall not swear falsely, and you shall fulfil to the Lord your oaths — a conflation of Lev 19:12 (<em>ou pseudorkēseis</em>) and Num 30:2 (fulfilling vows to the LORD). In Second Temple Judaism elaborate systems of oath-taking had developed to classify binding versus non-binding oaths by formula (cf. Matt 23:16-22). Jesus addresses the whole practice rather than the classification system.</p>',
    "34": '<p><strong>mē omosai holōs</strong> — do not swear at all (<em>holōs</em>, altogether, at all) — the adverb makes the prohibition comprehensive. <em>Mēte en tō ouranō</em> — neither by heaven — the escalating list of oath-objects (heaven, earth, Jerusalem, one\'s own head) all fail for the same reason: none are fully in human control. <em>Thronos gar estin tou theou</em> — for it is the throne of God — heaven is already defined by its relationship to God and cannot be used as a neutral object of oath.</p>',
    "35": '<p><strong>mēte en tē gē, hoti hypopodion estin tōn podōn autou</strong> — nor by the earth, for it is his footstool — drawing on Isa 66:1 (<em>hē gē hypopodion tōn podōn mou</em>). <em>Mēte eis Hierosolyma</em> — nor by Jerusalem — <em>hoti polis estin tou megalou basileōs</em> — for it is the city of the Great King — from Ps 48:2 (LXX 47:3). Both OT references are cited without attribution, assuming audience recognition. The logic: any oath-object that belongs to God cannot be invoked independently of God.</p>',
    "36": '<p><strong>mēte en tē kephalē sou omosēs</strong> — nor swear by your head — the most personal oath-object, but also not within human control. <em>Hoti ou dynastai mian tricha leukēn poiēsai ē melainan</em> — because you cannot make one hair white or black — <em>dynastai</em> present: a permanent incapacity. The inability to control one\'s own hair color is the argument: if you cannot govern even that, your head is not an adequate basis for an oath.</p>',
    "37": '<p><strong>estō de ho logos hymōn nai nai, ou ou</strong> — let your word be "yes yes, no no" — <em>estō</em> third-person imperative of <em>eimi</em>: let it be. The reduplication is emphatic affirmation/negation rather than a prescribed formula. <em>To de perisson toutōn ek tou ponērou estin</em> — anything beyond these comes from the evil one (or: from evil) — <em>ek tou ponērou</em>: the article allows both readings; Matthew\'s usage elsewhere (6:13, <em>apo tou ponērou</em>) tends toward the personal referent (the devil).</p>',
    "38": '<p><strong>ophthalmon anti ophthalmou kai odonta anti odontos</strong> — eye for eye and tooth for tooth — the <em>lex talionis</em>, cited from Exod 21:24 / Lev 24:20 / Deut 19:21. In its original legislative context this was a principle of proportionate justice limiting disproportionate revenge; Jesus addresses not the legal system but the personal disposition of retaliation that the formula had come to sanction in popular ethics.</p>',
    "39": '<p><strong>mē antistēnai tō ponērō</strong> — do not resist the evil one/person (<em>anthistēmi</em> aorist infinitive) — <em>tō ponērō</em> is ambiguous: it can be the evil person (the one who wrongs you) or the evil one (the devil). The examples that follow suggest a human adversary. <em>Rhapizō</em> — slap/strike — the right cheek specified (<em>tēn dexian siagona</em>) suggests a backhanded blow, which in Roman-era culture was a gesture of particular contempt rather than a serious assault.</p>',
    "40": '<p><strong>tō thelonti soi krithēnai kai ton chitōna sou labein</strong> — to the one who wants to sue you and take your tunic — <em>krinō</em> in the legal sense. <em>Chitōn</em> is the inner tunic; <em>himation</em> is the outer cloak. The cloak was more valuable (it doubled as a blanket) and legally protected from permanent seizure as a pledge (Exod 22:26-27). Jesus inverts the legal protection: surrender the more-protected garment voluntarily, beyond what the lawsuit demands.</p>',
    "41": '<p><strong>angareusei se milion hen</strong> — compels you to go one mile — <em>angareuo</em> is a loanword from Persian through Aramaic: the requisition of civilian labor or transport by military or imperial authority (cf. 27:32, Simon of Cyrene compelled to carry the cross). <em>Milion</em> — a Roman mile (approximately 1.48 km). The right of military requisition was a source of everyday resentment under Roman occupation; Jesus reframes compelled service as a site of voluntary extension.</p>',
    "42": '<p><strong>tō aitounti se dos</strong> — give to the one who asks you — <em>dos</em> aorist imperative: decisive action. <em>Ton thelonta apo sou daneisasthai mē apostraphēs</em> — do not turn away from the one who wants to borrow from you — <em>apostraphēs</em> aorist passive subjunctive of <em>apostrephō</em>: to turn away, refuse. The contrast with vv.38-41 is noteworthy: those verses address forced or hostile demands; this verse addresses voluntary requests, extending the principle to generosity.</p>',
    "43": '<p><strong>agapēseis ton plēsion sou</strong> — you shall love your neighbor (<em>agapaō</em>) — from Lev 19:18. <em>Ton plēsion</em> — the neighbor — the LXX term for the fellow-Israelite (or resident alien) covered by covenant obligation. <strong>Kai misēseis ton echthron sou</strong> — and hate your enemy — this second clause is not found in the Torah; it represents a popular inference that restricted the scope of "neighbor" to exclude enemies. Jesus addresses the interpretation, not a scriptural citation.</p>',
    "44": '<p><strong>agapate tous echthrous hymōn</strong> — love your enemies (<em>agapaō</em> present imperative, ongoing action) — the extension of <em>agapē</em> to enemies is the pivot of the antithesis. <em>Proseuchesthe hyper tōn diōkontōn hymas</em> — pray for those who persecute you — <em>proseuchomai</em> present imperative: ongoing intercession, not a one-time prayer. The combination of love and prayer as active dispositions toward enemies marks the qualitative difference from the reciprocal-love of v.46.</p>',
    "45": '<p><strong>hopōs genesthe huioi tou patros hymōn</strong> — so that you may become sons of your Father — <em>genesthe</em> aorist subjunctive: the purpose clause points to a transformation, a becoming. <em>Ton hēlion autou anatellei epi ponērous kai agathous</em> — he causes his sun to rise on evil and good — <em>anatellō</em> causative: God is the agent of the sun\'s rising. <em>Brechei epi dikaious kai adikous</em> — sends rain on righteous and unrighteous. The non-discriminating character of God\'s common grace becomes the model for the disciples\' non-discriminating love.</p>',
    "46": '<p><strong>ean agapate tous agapōntas hymas</strong> — if you love those who love you — conditional with <em>agapaō</em> present participle: those who are actively loving you back. <em>Tina misthon echete</em> — what reward (<em>misthos</em>, wages owed) do you have? <em>Ouchi kai hoi telōnai to auto poiousin</em> — do not even the tax collectors do the same? — <em>telōnai</em> were toll-collectors in the service of Herod or Rome, despised as collaborators and extortionists; they represent the moral low bar of the surrounding culture.</p>',
    "47": '<p><strong>ean aspassēsthe tous adelphous hymōn monon</strong> — if you greet only your own people — <em>aspasēsthe</em> aorist subjunctive of <em>aspazomai</em>; greeting in ancient Mediterranean culture was a formal acknowledgment of social relationship and mutual obligation, not a casual pleasantry. Restricting greeting to one\'s own group was a form of social boundary maintenance. <em>Ti perisson poieite</em> — what are you doing more than others (<em>perisson</em> = extra, exceptional)? <em>Ouchi kai hoi ethnikoi to auto poiousin</em> — do not even the Gentiles do the same? — Gentiles, like tax collectors in v.46, represent the lowest comparable moral baseline.</p>'
  },
  "6": {
    "1": '<p><strong>tēn dikaiosynēn hymōn mē poiein emprosthen tōn anthrōpōn</strong> — do not perform your righteousness before people — <em>dikaiosynē</em> here governs the three practices that follow (almsgiving, prayer, fasting); it is the broader category of covenant faithfulness, not righteousness as legal standing. <em>Theathēnai autois</em> — to be seen by them — aorist infinitive of purpose: the audience-seeking is the problem, not the practice itself. <em>Misthon ouk echete para tō patri hymōn</em> — you have no reward from your Father — the reward from God and the reward from human observers are mutually exclusive.</p>',
    "2": '<p><strong>mē salpises emprosthen sou hōsper hoi hypokritai poiousin</strong> — do not sound a trumpet before you as the hypocrites do — <em>hypokritai</em> is from <em>hypokrinomai</em>, to play a theatrical role; in Hellenistic Greek, a theater actor. Jesus applies it to religious performance where the inner motive contradicts the outer act. <strong>Apechousin ton misthon autōn</strong> — they have received their reward in full — <em>apechō</em> is the technical term from papyrus receipts: "paid in full." The heavenly ledger shows zero balance; they have been paid entirely by human applause.</p>',
    "3": '<p><strong>mē gnōtō hē aristera sou ti poiei hē dexia sou</strong> — do not let your left hand know what your right hand is doing — <em>gnōtō</em> third-person aorist imperative: let it not know. The image targets the reflex of self-congratulation: even internal awareness of one\'s own generosity becomes a form of self-audience. The left hand (<em>aristera</em>) and right hand (<em>dexia</em>) are the same person\'s own faculties; the command points to unawareness of self as the ideal of pure giving.</p>',
    "4": '<p><strong>hopōs ē sou hē eleēmosynē en tō kryptō</strong> — so that your giving may be in secret (<em>kryptos</em>, hidden) — the purpose clause governs the action: secrecy is the goal, not a byproduct. <em>Ho patēr sou ho blepōn en tō kryptō apodōsei soi</em> — your Father who sees in secret will reward you — <em>blepōn</em> present participle: ongoing active observation; <em>apodōsei</em> future: certain future payment. The Father\'s observation substitutes completely for human observation.</p>',
    "5": '<p><strong>hoi hypokritai philousin</strong> — the hypocrites love — <em>phileō</em> (love by affection/inclination) rather than <em>agapaō</em>; they are drawn to public prayer by desire, not duty. <em>Stantontes en tais synagōgais kai en tais gōniais tōn plateiōn proseuchesthai</em> — standing in the synagogues and on the street corners to pray — <em>stantontes</em> is a perfect active participle (<em>histamai</em>): having taken their stand, remaining standing. The position is deliberate and held. <em>Apechousin</em> — paid in full — same receipt-formula as v.2.</p>',
    "6": '<p><strong>tameion</strong> — inner room, storeroom — a private interior room, often windowless, used for storage; the most private space in a household. <em>Kleisas tēn thyran sou</em> — having shut your door — <em>kleisas</em> aorist participle: the closed door is a precondition, not an afterthought. <em>Proseuxai tō patri sou tō en tō kryptō</em> — pray to your Father who is in secret — the Father inhabits the hidden space; he is present in the hiddenness itself. <em>Ho blepōn en tō kryptō apodōsei soi</em> — identical reward-formula to 6:4.</p>',
    "7": '<p><strong>battalogēsēte</strong> — do not babble (<em>battologeō</em>) — a verb found almost nowhere in classical Greek, likely onomatopoeic: stuttering, repeating nonsense syllables. <em>Hōsper hoi ethnikoi</em> — like the Gentiles — pagan prayer often involved extensive repetition of divine names and epithets to compel divine attention. <em>Dokousin gar hoti en tē polylogia autōn eisakousthēsontai</em> — for they think that by their many words (<em>polylogia</em>, a word coined for the occasion) they will be heard — the theology of prayer-by-volume contrasted with address to a Father who already knows.</p>',
    "8": '<p><strong>oiden ho patēr hymōn hōn chreian echete</strong> — your Father knows what you need — <em>oiden</em> is a perfect form used as a present: the Father\'s knowledge is complete and current. <em>Pro tou hymas aitēsai auton</em> — before you ask him — prayer is not informational; it is relational. Prayer does not supply God with data he lacks but is the mode of relationship in which the Father\'s foreknowledge becomes the context for the disciple\'s dependence.</p>',
    "10": '<p><strong>elthatō hē basileia sou</strong> — let your kingdom come (<em>elthátō</em> aorist imperative of <em>erchomai</em>) — the petition is eschatological: the full arrival of the reign of God. <em>Genēthētō to thelēma sou</em> — let your will be done (<em>genēthētō</em> aorist passive imperative of <em>ginomai</em>): let it come to be. <em>Hōs en ouranō kai epi gēs</em> — as in heaven, so also on earth — the adverbial phrase qualifies how the will is to be done: the manner of heavenly obedience is the standard for earthly obedience.</p>',
    "11": '<p><strong>ton arton hēmōn ton epiousion dos hēmin sēmeron</strong> — give us today our daily bread — <em>epiousion</em> (G1967) is one of the rarest words in the Greek New Testament, found almost nowhere outside this prayer and its Lukan parallel (11:3). It may derive from <em>epi + ousia</em> (for existence: the bread necessary for existence) or <em>epi + iōn</em> (for the coming day: tomorrow\'s bread). Origen noted that the word did not exist in classical Greek, suggesting it was coined for the prayer. The MKT "daily" follows the most common rendering; "necessary for existence" or "for the coming day" are defensible alternatives.</p>',
    "13": '<p><strong>mē eisenenkēs hēmas eis peirasmon</strong> — do not lead us into temptation/testing (<em>peirasmos</em>) — <em>eisenenkēs</em> aorist active subjunctive: a point-action. <em>Peirasmos</em> covers both testing (a trial through which faith is proved) and temptation (an inducement to sin); the petition covers both senses. <em>Alla rhysai hēmas apo tou ponērou</em> — but deliver us from the evil one — <em>rhysai</em> aorist imperative of <em>rhyomai</em> (to rescue from danger); <em>apo tou ponērou</em> likely personal (cf. 5:37). The doxology (<em>hoti sou estin hē basileia</em>) is well-attested in later manuscripts but absent from the earliest witnesses (Sinaiticus, Vaticanus).</p>',
    "14": '<p><strong>ean gar aphēte tois anthrōpois ta paraptōmata autōn</strong> — for if you forgive people their trespasses — <em>paraptōmata</em> (G3900, from <em>parapiptō</em>, to fall beside/astray): trespasses, moral deviations — a different word from <em>opheilēmata</em> (debts) in v.12. <em>Aphēte</em> aorist active subjunctive: a decisive act of forgiveness. <em>Aphēsei kai hymin ho patēr hymōn ho ouranios</em> — your heavenly Father will also forgive you — the correlation is conditional, not commercial; human forgiveness is evidence of a heart transformed by divine forgiveness, not its cause.</p>',
    "15": '<p><strong>ean de mē aphēte tois anthrōpois</strong> — but if you do not forgive people — the negative counterpart to v.14 using the same subjunctive construction. <em>Oude ho patēr hymōn aphēsei ta paraptōmata hymōn</em> — neither will your Father forgive your trespasses — the conditional symmetry means that withholding forgiveness reveals a heart that has not received forgiveness at depth (cf. 18:23-35, the unforgiving servant), not that human forgiveness earns divine forgiveness.</p>',
    "16": '<p><strong>nēsteuēte mē ginesthe hōsper hoi hypokritai skythropoi</strong> — when you fast, do not become like the hypocrites, gloomy-faced — <em>skythropoi</em> (gloomy, sullen: <em>skythros</em> + <em>ōps</em>/face) appears in the LXX of Gen 40:7 for the cup-bearer\'s distress. <em>Aphanizousin gar ta prosōpa autōn</em> — for they disfigure their faces (<em>aphanizō</em>, to make unseen/disappear) — they obscure their faces to make their piety visible; the irony: they make their faces invisible in order to be seen. <em>Apechousin</em> — paid in full — same formula as 6:2, 5.</p>',
    "17": '<p><strong>su de nēsteuōn aleipsai sou tēn kephalēn kai to prosōpon sou nipsai</strong> — but when you fast, anoint your head and wash your face — <em>aleipsai</em> aorist middle imperative of <em>aleiphō</em> (to anoint with oil): anointing the head was a sign of festivity, not mourning (Ps 23:5; Ruth 3:3). <em>Nipsai</em> aorist middle imperative of <em>niptō</em> (to wash). The commands describe normal daily grooming; Jesus instructs disciples to look normal, i.e., to conceal the fast from human observers entirely.</p>',
    "18": '<p><strong>hopōs mē phanēs tois anthrōpois nēsteuōn</strong> — so that you may not appear to be fasting to people — <em>phanēs</em> aorist passive subjunctive of <em>phainō</em>: appear, be visible. The purpose of normal grooming is concealment of the practice. <em>Ho patēr sou ho blepōn en tō kryptō apodōsei soi</em> — identical reward-formula to 6:4 and 6:6; the three practices of piety (alms, prayer, fasting) receive the identical structural treatment.</p>',
    "19": '<p><strong>mē thēsaurizete hymin thēsaurous epi tēs gēs</strong> — do not store up treasures for yourselves on earth (<em>thēsaurizete</em> present imperative: stop the ongoing practice) — <em>hopou sēs kai brōsis aphanizei</em> — where moth and corrosion destroys — <em>sēs</em> (moth, the insect that consumes fabric); <em>brōsis</em> (eating, corrosion — used for rust or vermin gnawing grain). <em>Kai hopou kleptai dioryssousin</em> — and where thieves dig through (<em>dioryssō</em>) — thieves in ancient Palestine literally dug through the mud-brick walls of homes rather than forcing doors.</p>',
    "20": '<p><strong>thēsaurizete de hymin thēsaurous en ouranō</strong> — but store up for yourselves treasures in heaven — the positive counterpart to v.19 with the same verb <em>thēsaurizete</em> (present imperative); the contrast is location, not activity. <em>Hopou oute sēs oute brōsis aphanizei, kai hopou kleptai ou dioryssousin</em> — the negative catalogue reverses v.19 point by point. The treasure-in-heaven language draws on Jewish tradition (Tob 4:9; Pss. Sol. 9:5) where righteous deeds credited before God constitute heavenly wealth.</p>',
    "21": '<p><strong>hopou gar estin ho thēsauros sou, ekei estai kai hē kardia sou</strong> — for where your treasure is, there your heart will be also — <em>thēsauros</em> and <em>kardia</em> are linked by the directional <em>hopou/ekei</em> (where/there). This reverses the expected psychology: one might expect "where your heart is, there you will put your treasure." Jesus says that what you invest in determines what you care about. The <em>kardia</em> is the center of loyalty and attention, not merely emotion.</p>',
    "22": '<p><strong>ho lychnos tou sōmatos estin ho ophthalmos</strong> — the lamp of the body is the eye — the body is illuminated by a single opening. <em>Ean oun ē ho ophthalmos sou haplous</em> — if then your eye is <em>haplous</em> — <em>haplous</em> (G573) means single, undivided, and in Jewish idiom generous (in contrast to the "evil eye" of v.23 which denotes stinginess); both senses are active here. <em>Holon to sōma sou phōteinon estai</em> — your whole body will be full of light — the single eye illuminates the entire body; the eye metaphor carries the treasure/heart teaching of vv.19-21 into the language of perception.</p>',
    "23": '<p><strong>ean de ho ophthalmos sou ponēros ē</strong> — but if your eye is evil/diseased — <em>ponēros</em> (evil, and: diseased, not functioning properly). In Jewish idiom, the "evil eye" (<em>ayin ra</em>) denoted stinginess or greed; the "good eye" (<em>ayin tob</em>) denoted generosity. Both the functional (seeing clearly/poorly) and the moral (generous/stingy) dimensions are present. <em>Ei oun to phōs to en soi skotos estin, to skotos poson</em> — if then the light that is in you is darkness, how great is that darkness — the rhetorical question uses the impossible image (a darkness that functions as light) to measure the magnitude of the self-deception.</p>',
    "25": '<p><strong>mē merimnate tē psychē hymōn ti phagēte ē ti piēte</strong> — do not be anxious (<em>merimnaō</em>, present imperative: stop the ongoing anxiety) about your life/soul, what you will eat or drink — <em>psychē</em> (G5590) here = life, the physical life sustained by food and drink. <em>Mēde tō sōmati hymōn ti endysēsthe</em> — nor for your body what you will put on. <em>Ouchi hē psychē pleon estin tēs trophēs</em> — is not life more than food? — a <em>qal va-chomer</em> (light-to-heavy) argument: if God provided the greater thing (life itself), will he not provide the lesser things that sustain it?</p>',
    "26": '<p><strong>emblepate eis ta peteina tou ouranou</strong> — look carefully at the birds of the air (<em>emblepō</em>, to look into/at intently — stronger than <em>blepō</em>) — the birds are not examples of industriousness but of provision despite having no storage system: <em>ou speirousin oude therizousin oude synagousin eis apothēkas</em> — they neither sow nor reap nor gather into barns. <em>Ho patēr hymōn ho ouranios trephei auta</em> — your heavenly Father feeds them. <em>Ouch hymeis mallon diapherete autōn</em> — are you not worth much more than they — <em>diapherō</em>, to differ in value.</p>',
    "27": '<p><strong>tis de ex hymōn merimnōn dynastai prostheinai epi tēn hēlikian autou pēchyn hena</strong> — which of you by worrying can add a single cubit to his span of life — <em>hēlikia</em> can mean height (stature) or lifespan; in context "span of life" makes better sense (adding a cubit to one\'s stature is trivial; adding time to one\'s lifespan is what worry seeks). <em>Pēchys</em> (a cubit, about 45 cm) applied to time is a small unit. The rhetorical question expects "no one."</p>',
    "28": '<p><strong>ta krina tou agrou</strong> — the lilies/flowers of the field — <em>krinon</em> (G2918) likely refers to wildflowers broadly; archaeological work suggests the scarlet anemone or similar field flowers of Galilee, not necessarily the iris or water lily. <em>Katamathete</em> — observe carefully (<em>katamanthanō</em>, a stronger compound of <em>manthanō</em>, to learn) — learn by observation. <em>Pōs auxanousin</em> — how they grow — present indicative. <em>Ou kopiōsi oude nēthousin</em> — they do not labor nor do they spin — the activities of human textile production are absent from the flowers.</p>',
    "29": '<p><strong>Solomōn en pasē tē doxē autou</strong> — Solomon in all his glory — <em>doxa</em> here = splendor, the visual manifestation of honor and wealth. Solomon\'s legendary wealth (1 Kgs 10) is the superlative of human magnificence. <em>Ou periebleto hōs hen toutōn</em> — was not clothed like one of these — <em>periballō</em> (to clothe, wrap around) aorist passive; Solomon as a passive recipient of clothing, compared unfavorably to what God clothes wild flowers with. The understatement makes the point more striking.</p>',
    "30": '<p><strong>ton chorton tou agrou sēmeron onta kai aurion eis klibanon ballomenon</strong> — the grass of the field, which is here today and tomorrow thrown into the oven — <em>chortos</em> (grass, hay) encompasses lilies and common grass; <em>klibanon</em> is a clay pot or dome used as an oven, into which dried grass was thrown as fuel. <strong>Oligopistoi</strong> — O you of little faith — a compound word: <em>oligos</em> (little) + <em>pistis</em> (faith/trust); Matthew uses it as Jesus\'s characteristic address to disciples in distress (8:26; 14:31; 16:8; 17:20). The diminutive is corrective, not contemptuous.</p>',
    "31": '<p><strong>mē oun merimnēsēte legontes</strong> — do not therefore be anxious, saying — <em>merimnēsēte</em> aorist subjunctive: a prohibition against taking up anxiety as a posture. The three quoted worries (<em>ti phagōmen, ti piōmen, ti peribalōmetha</em> — what shall we eat? what shall we drink? what shall we wear?) are subjunctive deliberatives: the internal questions of anxious deliberation. Jesus quotes the exact questions the anxious person asks herself, making the prohibition specific and recognizable.</p>',
    "32": '<p><strong>panta gar tauta ta ethnē epizētousin</strong> — for the Gentiles seek all these things (<em>epizēteō</em>, to seek after earnestly) — the <em>ethnē</em> here are not moral exemplars but the non-covenant people who have no framework for trusting a providential Father. <em>Oiden gar ho patēr hymōn ho ouranios hoti chrēzete toutōn hapantōn</em> — for your heavenly Father knows that you need all these things — the same foreknowledge as 6:8 (<em>oiden</em> perfect-as-present); the Father\'s prior knowledge removes the cognitive urgency for anxiety.</p>',
    "33": '<p><strong>zēteite de prōton tēn basileian tou theou kai tēn dikaiosynēn autou</strong> — seek first his kingdom and his righteousness — <em>zēteite</em> present imperative, contrasting with the anxious seeking of v.32; <em>prōton</em> sets the priority. <em>Tēn dikaiosynēn autou</em> — his righteousness — <em>autou</em> can be objective (the righteousness God requires) or subjective (the righteousness God himself displays); the MKT "his righteousness" preserves the ambiguity. <em>Tauta panta prostethēsetai hymin</em> — all these things will be added to you — <em>prostithēmi</em> future passive: provision comes as an addition to, not a substitute for, seeking the kingdom.</p>',
    "34": '<p><strong>mē oun merimnēsēte eis tēn aurion</strong> — do not therefore be anxious about tomorrow — <em>eis tēn aurion</em> projects anxiety forward in time. <em>Hē gar aurion merimnēsei heautēs</em> — for tomorrow will be anxious for itself (<em>heautēs</em> reflexive genitive) — a personification of tomorrow as an agent carrying its own burden. <em>Arketon tē hēmera hē kakia autēs</em> — sufficient for the day is its own trouble — <em>arketos</em> (sufficient, from <em>arkeō</em>) + <em>kakia</em> (evil, trouble, hardship): the day\'s troubles are already enough; accumulating tomorrow\'s troubles before tomorrow arrives is unnecessary addition.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-original', 'matthew', existing)
    print('Matthew 5-6 mkt-original written.')

if __name__ == '__main__':
    main()
